/*
 * AI generated by GitHub Copilot - DeepSeek V4 Flash
 *
 * Check raw HID reports for macro triggers and execute if matched.
 *
 * A macro triggers when:
 *   - A specific key is newly pressed (was absent in old_report,
 *     present in new_report)
 *   - While specific modifier bits are held (checked via mod_mask)
 *
 * When triggered, the macro's step sequence is written to hid_output_fd
 * as a series of HID reports (report_id=1). The caller should skip
 * normal forwarding of this report.
 *
 * Returns true if a macro was executed.
 */
bool check_and_execute_macro(const unsigned char* old_report,
                              const unsigned char* new_report,
                              int hid_output_fd) {
    uint8_t new_mod = new_report[0];

    // Collect keys that are NEWLY pressed (in new_report but not old_report)
    uint8_t new_keys[6];
    int new_count = 0;

    for (int i = 2; i < KEYBOARD_HID_REPORT_SIZE; i++) {
        uint8_t k = new_report[i];
        if (k == 0) continue;
        bool was_in_old = false;
        for (int j = 2; j < KEYBOARD_HID_REPORT_SIZE; j++) {
            if (old_report[j] == k) { was_in_old = true; break; }
        }
        if (!was_in_old) {
            if (new_count < 6) new_keys[new_count++] = k;
        }
    }

    // Also detect modifier-bit changes (e.g. a modifier key just pressed)
    uint8_t old_mod = old_report[0];
    uint8_t new_mod_bits = new_mod & ~old_mod;  // bits just turned on

    // Check each macro
    for (const auto& macro : macros) {
        // Check modifier mask match
        if ((new_mod & macro.mod_mask) != (macro.trigger_mod & macro.mod_mask))
            continue;

        // For keycode trigger: check if trigger_key was newly pressed
        if (macro.trigger_key != 0) {
            bool found = false;
            for (int i = 0; i < new_count; i++) {
                if (new_keys[i] == macro.trigger_key) {
                    found = true;
                    break;
                }
            }
            if (!found) continue;
        }

        // Macro triggered! Write the step sequence to HID output.
        // Format: [report_id=1] [modifier] [reserved=0] [6 keycodes]
        unsigned char hid_report[KEYBOARD_HID_REPORT_SIZE + 1];
        hid_report[0] = 1;  // report_id

        for (const auto& step : macro.steps) {
            memset(hid_report + 1, 0, KEYBOARD_HID_REPORT_SIZE);
            hid_report[1] = step.modifier;  // byte 1 = modifier
            // byte 2 is reserved (0x00)
            memcpy(hid_report + 3, step.keys, 6);  // bytes 3-8
            // Retry on EAGAIN — USB endpoint may be busy
            int retries = 50;
            while (retries-- > 0) {
                ssize_t wr = write(hid_output_fd, hid_report,
                                   KEYBOARD_HID_REPORT_SIZE + 1);
                if (wr >= 0) break;
                if (errno == EAGAIN) {
                    usleep(1000);  // 1ms, then retry
                } else {
                    break;  // real error, give up
                }
            }
            if (step.delay_us > 0) {
                usleep(step.delay_us);
            }
        }

        return true;
    }

    return false;
}
