/*
 * AI generated by GitHub Copilot - DeepSeek V4 Flash
 *
 * JSON config file loader for keyboard layouts.
 *
 * Expected JSON format:
 * {
 *   "language": "Italian",
 *   "description": "...",
 *   "host_os": "windows",       // optional, for documentation
 *   "keycode_map": {            // optional, key remapping
 *     "44": "44",               // "from_code": "to_code" (decimal strings)
 *   },
 *   "macros": [                  // optional, key-sequence macros
 *     {
 *       "trigger": { "modifiers": 64, "keycode": 4, "mod_mask": 64 },
 *       "steps": [
 *         { "modifier": 4, "keys": [98], "delay_us": 15000 },
 *         ...
 *       ]
 *     }
 *   ]
 * }
 */
bool load_keymap_from_json(const std::string& path) {
    std::ifstream file(path);
    if (!file.is_open()) {
        std::cerr << "Error: cannot open config file: " << path << std::endl;
        return false;
    }

    json j;
    try {
        file >> j;
    } catch (const std::exception& e) {
        std::cerr << "Error parsing JSON: " << e.what() << std::endl;
        return false;
    }

    // --- Load keycode_map ---
    if (j.contains("keycode_map")) {
        auto& km = j["keycode_map"];
        for (auto it = km.begin(); it != km.end(); ++it) {
            int from_code = std::stoi(it.key(), nullptr, 0);
            if (it.value().is_null()) {
                keycode_map[from_code] = 0;  // null = pass-through
            } else {
                keycode_map[from_code] = static_cast<uint8_t>(
                    std::stoi(it.value().get<std::string>(), nullptr, 0));
            }
        }
    }

    // --- Load macros ---
    if (j.contains("macros")) {
        for (const auto& m : j["macros"]) {
            uint8_t trig_mod = m["trigger"]["modifiers"].get<int>();
            uint8_t trig_key = m["trigger"]["keycode"].get<int>();
            uint8_t mod_mask = m["trigger"].value("mod_mask", 0xFF);

            std::vector<MacroStep> steps;
            for (const auto& s : m["steps"]) {
                MacroStep step;
                step.modifier = s["modifier"].get<int>();
                memset(step.keys, 0, 6);
                if (s.contains("keys")) {
                    int idx = 0;
                    for (const auto& k : s["keys"]) {
                        if (idx < 6) step.keys[idx++] = k.get<int>();
                    }
                }
                step.delay_us = s.value("delay_us", 0);
                steps.push_back(step);
            }

            add_macro(trig_mod, trig_key, mod_mask, std::move(steps));
        }
    }

    if (j.contains("description")) {
        std::cout << "Config: " << j["description"].get<std::string>() << std::endl;
    }
    std::cout << "Loaded config from " << path << ": "
              << macros.size() << " macros" << std::endl;
    return true;
}
