/*
 * AI generated by GitHub Copilot - DeepSeek V4 Flash
 *
 * Build an Alt+numpad HID report sequence for a given decimal code.
 * Returns a vector of MacroSteps.
 *
 * Example: code=224 produces steps for Alt+0224 (à).
 */
static std::vector<MacroStep> build_alt_numpad_sequence(int decimal_code) {
    // Digits of the decimal code (e.g. 224 -> {2, 2, 4})
    int digits[8];
    int digit_count = 0;
    int tmp = decimal_code;
    while (tmp > 0) {
        digits[digit_count++] = tmp % 10;
        tmp /= 10;
    }
    // Reverse to get most-significant first
    for (int i = 0; i < digit_count / 2; i++) {
        int t = digits[i];
        digits[i] = digits[digit_count - 1 - i];
        digits[digit_count - 1 - i] = t;
    }

    // Numpad HID keycodes for digits 0-9
    static const uint8_t numpad_keys[] = {
        0x62, 0x59, 0x5A, 0x5B, 0x5C, 0x5D, 0x5E, 0x5F, 0x60, 0x61
    };

    std::vector<MacroStep> steps;

    // Step: Press LeftAlt alone
    MacroStep s;
    s.modifier = 0x04;
    memset(s.keys, 0, 6);
    s.delay_us = 20000;
    steps.push_back(s);

    // Steps for each digit: press numpad key, then release
    for (int d = 0; d < digit_count; d++) {
        MacroStep press;
        press.modifier = 0x04;
        memset(press.keys, 0, 6);
        press.keys[0] = numpad_keys[digits[d]];
        press.delay_us = 15000;
        steps.push_back(press);

        MacroStep release;
        release.modifier = 0x04;
        memset(release.keys, 0, 6);
        release.delay_us = 10000;
        steps.push_back(release);
    }

    // Final step: release LeftAlt
    MacroStep finish;
    finish.modifier = 0x00;
    memset(finish.keys, 0, 6);
    finish.delay_us = 0;
    steps.push_back(finish);

    return steps;
}


/*
 * AI generated by GitHub Copilot - DeepSeek V4 Flash
 *
 * Register macros for an accented character with proper modifier masking.
 *
 * For AltGr variants (no Shift):  trigger_mod=0x40, mod_mask=0x40
 * For AltGr+Shift variants:       trigger_mod=0x42, mod_mask=0x42
 *
 * Shift-requiring macros are registered FIRST so they are checked
 * before the unshifted variant. This ensures AltGr+Shift+E matches
 * é (requires Shift) instead of è (matches without Shift).
 *
 * Each variant is registered twice: once for RightAlt (0x40) and
 * once for LeftAlt (0x04), to support different keyboard types.
 */

struct CharMap {
    uint8_t key;       // HID keycode
    int  alt_code;     // Windows Alt+numpad decimal code
    bool need_shift;   // true = requires Shift, false = no Shift
};

static void register_char_macros(const CharMap& ch) {
    auto steps = build_alt_numpad_sequence(ch.alt_code);
    if (steps.empty()) return;

    uint8_t mod = ch.need_shift ? 0x42 : 0x40;
    uint8_t mask = ch.need_shift ? 0x42 : 0x40;

    add_macro(mod, ch.key, mask, steps);                    // RightAlt (+ Shift)
    add_macro(mod & ~0x40 | 0x04, ch.key, mask & ~0x40 | 0x04,
              std::move(steps));                             // LeftAlt (+ Shift)
}


void load_keymap_italian() {
    // --- Approach: Host-side Italian layout + raw forwarding ---
    //
    // This config expects the HOST PC to have its keyboard layout set
    // to Italian.  The Pi forwards RAW HID scan codes (no remapping)
    // so that each physical key position produces the character that
    // an Italian keyboard would have at that position.
    //
    // On the Pi 500's UK keyboard, the Italian characters appear at:
    //   [è] at the [ key      [ò] at the ; key      [à] at the ' key
    //   [ù] at the \ key      [ì] at the = key      [é] at Shift+[
    //
    // Keycode_map is all-zeros (identity) — raw pass-through.
    //
    // --- Macros for chars NOT on standard Italian layout ---
    // Characters like ç, ê, ë, ï, ñ, ô, ö, û, ü, ÿ require AltGr or
    // compose sequences on ANY standard layout.  The AltGr macros below
    // inject Alt+numpad codes so they work when the host is Windows.

    // Chars that need AltGr even on a real Italian keyboard:
    // ç, ê, ë, ï, ñ, ô, ö, û, ü, ÿ
    // Also uppercase variants: Ç, Ê, Ë, Ï, Ñ, Ô, Ö, Û, Ü, Ÿ

    // Extended chars mapped to letter keys via AltGr:
    // AltGr + C → ç (231)    AltGr+Shift + C → Ç (199)
    // AltGr + E → ê (234)    AltGr+Shift + E → Ê (202)
    // AltGr + I → ï (239)    AltGr+Shift + I → Ï (207)
    // AltGr + N → ñ (241)    AltGr+Shift + N → Ñ (209)
    // AltGr + O → ô (244)    AltGr+Shift + O → Ô (212)
    // AltGr + R → ë (235)    AltGr+Shift + R → Ë (203)
    // AltGr + U → û (251)    AltGr+Shift + U → Û (219)
    // AltGr + Y → ü (252)    AltGr+Shift + Y → Ü (220)
    // AltGr + Shift + ? → Ÿ (159) on ... key

    // Note: è, é, à, ò, ù, ì are NOT registered as macros because they
    // are directly available via Italian host layout with raw forwarding.
    // Remove this line to also register them as AltGr macros.

    struct { uint8_t key; int code; bool shift; } extended[] = {
        {0x06, 231, false},  // C → ç
        {0x06, 199, true},   // C+Shift → Ç
        {0x08, 234, false},  // E → ê
        {0x08, 202, true},   // E+Shift → Ê
        {0x0A, 239, false},  // I → ï
        {0x0A, 207, true},   // I+Shift → Ï
        {0x11, 241, false},  // N → ñ
        {0x11, 209, true},   // N+Shift → Ñ
        {0x12, 244, false},  // O → ô
        {0x12, 212, true},   // O+Shift → Ô
        {0x13, 235, false},  // R → ë
        {0x13, 203, true},   // R+Shift → Ë
        {0x15, 251, false},  // U → û
        {0x15, 219, true},   // U+Shift → Û
        {0x1A, 252, false},  // Y → ü
        {0x1A, 220, true},   // Y+Shift → Ü
    };

    for (auto& ch : extended) {
        CharMap cm = {ch.key, ch.code, ch.shift};
        register_char_macros(cm);
    }

    std::cout << "Loaded Italian layout: raw forwarding + "
              << macros.size() << " AltGr macros for extended chars"
              << std::endl;
    std::cout << "  Set host PC keyboard layout to Italian for best results." << std::endl;
    std::cout << "  UK physical positions: [=è  ;=ò  '=à  \\=ù  ==ì  Shift+[=é" << std::endl;
    std::cout << "  AltGr+C=ç  AltGr+E=ê  AltGr+I=ï  AltGr+N=ñ" << std::endl;
    std::cout << "  AltGr+O=ô  AltGr+R=ë  AltGr+U=û  AltGr+Y=ü" << std::endl;
}
